SELECT authors.au_id, authors.au_lname, authors.au_fname, authors.state, titles.title_id, titles.title, sales.qty, titles.price, titleauthor.royaltyper, (sales.qty * titles.price * titleauthor.royaltyper / 100) AS author_revenue FROM authors JOIN titleauthor ON authors.au_id = titleauthor.au_id JOIN titles ON titleauthor.title_id = titles.title_id JOIN sales ON titles.title_id = sales.title_id WHERE authors.state = 'CA'
